export * from './tree';
export * from './dynamic-tree';

export { Tree as default } from './tree';

'use client';

import * as React from 'react';

import { cn } from '@/lib/utils';
import { ChevronDownIcon, ChevronRightIcon } from '@/components/jetbrains-ui/icons';
import { ScrollArea, ScrollViewport } from '@/components/jetbrains-ui/scroll-area';
import './index.css';

type TreeContextValue = {
  selectedId: string | null;
  setSelectedId: (nextId: string) => void;
  expandedIds: Set<string>;
  toggleExpanded: (id: string, expanded?: boolean) => void;
  indent: number;
};

interface TreeProps extends React.ComponentPropsWithoutRef<'ul'> {
  selectedId?: string | null;
  defaultSelectedId?: string | null;
  onSelectedIdChange?: (id: string) => void;
  expandedIds?: string[];
  defaultExpandedIds?: string[];
  onExpandedIdsChange?: (ids: string[]) => void;
  indent?: number;
  width?: React.CSSProperties['width'];
  height?: React.CSSProperties['height'];
  scrollAreaClassName?: string;
}

interface TreeItemProps
  extends Omit<React.ComponentProps<'li'>, 'children' | 'id'> {
  value: string;
  label: React.ReactNode;
  icon?: React.ReactNode;
  endContent?: React.ReactNode;
  disabled?: boolean;
  children?: React.ReactNode;
}

const TreeContext = React.createContext<TreeContextValue | null>(null);
const TreeLevelContext = React.createContext(1);
const GROUP_COLLAPSE_DURATION = 180;

type TreeItemButtonStyle = React.CSSProperties & {
  '--jb-tree-item-padding-left': string;
};

function useTreeContext() {
  const context = React.useContext(TreeContext);

  if (!context) {
    throw new Error('Tree components must be used within <Tree>.');
  }

  return context;
}

function mergeExpandedIds(
  current: string[],
  id: string,
  expanded: boolean,
): string[] {
  const next = new Set(current);

  if (expanded) {
    next.add(id);
  } else {
    next.delete(id);
  }

  return Array.from(next);
}

function getTreeItemLabel(label: React.ReactNode, fallback: string) {
  if (typeof label === 'string') {
    return label;
  }

  return fallback;
}

function Tree({
  children,
  className,
  style,
  selectedId,
  defaultSelectedId = null,
  onSelectedIdChange,
  expandedIds,
  defaultExpandedIds = [],
  onExpandedIdsChange,
  indent = 16,
  width,
  height,
  scrollAreaClassName,
  ...props
}: TreeProps) {
  const [uncontrolledSelectedId, setUncontrolledSelectedId] = React.useState<
    string | null
  >(defaultSelectedId);
  const [uncontrolledExpandedIds, setUncontrolledExpandedIds] =
    React.useState<string[]>(defaultExpandedIds);

  const resolvedSelectedId =
    selectedId !== undefined ? selectedId : uncontrolledSelectedId;
  const resolvedExpandedIds =
    expandedIds !== undefined ? expandedIds : uncontrolledExpandedIds;

  const setSelectedId = React.useCallback(
    (nextId: string) => {
      if (selectedId === undefined) {
        setUncontrolledSelectedId(nextId);
      }

      onSelectedIdChange?.(nextId);
    },
    [onSelectedIdChange, selectedId],
  );

  const setExpandedIds = React.useCallback(
    (nextIds: string[]) => {
      if (expandedIds === undefined) {
        setUncontrolledExpandedIds(nextIds);
      }

      onExpandedIdsChange?.(nextIds);
    },
    [expandedIds, onExpandedIdsChange],
  );

  const toggleExpanded = React.useCallback(
    (id: string, expanded?: boolean) => {
      const isExpanded = resolvedExpandedIds.includes(id);
      const nextExpanded = expanded ?? !isExpanded;
      const nextIds = mergeExpandedIds(resolvedExpandedIds, id, nextExpanded);

      setExpandedIds(nextIds);
    },
    [resolvedExpandedIds, setExpandedIds],
  );

  const contextValue = React.useMemo<TreeContextValue>(
    () => ({
      selectedId: resolvedSelectedId,
      setSelectedId,
      expandedIds: new Set(resolvedExpandedIds),
      toggleExpanded,
      indent,
    }),
    [
      indent,
      resolvedExpandedIds,
      resolvedSelectedId,
      setSelectedId,
      toggleExpanded,
    ],
  );

  const treeList = (
    <ul
      data-slot="jb-tree"
      role="tree"
      className={cn(
        'jb-tree jb-static-tree m-0 list-none p-0 block w-full min-w-[244px] box-border py-2 text-[13px] leading-4 font-medium [font-family:var(--jb-font-sans),sans-serif]',
        className,
      )}
      style={style}
      {...props}
    >
      <TreeLevelContext.Provider value={1}>
        {children}
      </TreeLevelContext.Provider>
    </ul>
  );

  return (
    <TreeContext.Provider value={contextValue}>
      <ScrollArea
        data-slot="jb-tree-scroll-area"
        className={cn('max-w-full', scrollAreaClassName)}
        style={{ width, height }}
      >
        <ScrollViewport
          data-slot="jb-tree-scroll-viewport"
          className="size-full"
        >
          {treeList}
        </ScrollViewport>
      </ScrollArea>
    </TreeContext.Provider>
  );
}

function TreeItem({
  className,
  value,
  label,
  icon,
  endContent,
  disabled = false,
  children,
  ...props
}: TreeItemProps) {
  const { selectedId, setSelectedId, expandedIds, toggleExpanded, indent } =
    useTreeContext();
  const level = React.useContext(TreeLevelContext);

  const hasChildren = React.Children.count(children) > 0;
  const expanded = hasChildren ? expandedIds.has(value) : false;
  const selected = selectedId === value;
  const textLabel = getTreeItemLabel(label, value);
  const [keepGroupMounted, setKeepGroupMounted] = React.useState(expanded);
  const [groupExpanded, setGroupExpanded] = React.useState(expanded);
  const [isCollapsing, setIsCollapsing] = React.useState(false);
  const hasMountedRef = React.useRef(false);
  const collapseTimerRef = React.useRef<number | null>(null);
  const expandRafRef = React.useRef<number | null>(null);

  const rowPaddingLeft = 16 + (level - 1) * indent + Math.max(0, level - 2) * 2;
  const resolvedItemButtonStyle: TreeItemButtonStyle = {
    '--jb-tree-item-padding-left': `${rowPaddingLeft}px`,
  };

  const clearGroupAnimationHandles = React.useCallback(() => {
    if (collapseTimerRef.current !== null) {
      window.clearTimeout(collapseTimerRef.current);
      collapseTimerRef.current = null;
    }

    if (expandRafRef.current !== null) {
      window.cancelAnimationFrame(expandRafRef.current);
      expandRafRef.current = null;
    }
  }, []);

  React.useEffect(() => {
    return () => {
      clearGroupAnimationHandles();
    };
  }, [clearGroupAnimationHandles]);

  React.useEffect(() => {
    clearGroupAnimationHandles();

    if (!hasChildren) {
      setKeepGroupMounted(false);
      setGroupExpanded(false);
      setIsCollapsing(false);
      return;
    }

    if (!hasMountedRef.current) {
      hasMountedRef.current = true;
      setKeepGroupMounted(expanded);
      setGroupExpanded(expanded);
      setIsCollapsing(false);
      return;
    }

    if (expanded) {
      setKeepGroupMounted(true);
      setIsCollapsing(false);

      // Mount collapsed first, then expand on next frame so transition is visible.
      setGroupExpanded(false);
      expandRafRef.current = window.requestAnimationFrame(() => {
        expandRafRef.current = window.requestAnimationFrame(() => {
          setGroupExpanded(true);
          expandRafRef.current = null;
        });
      });

      return;
    }

    if (keepGroupMounted) {
      setGroupExpanded(false);
      setIsCollapsing(true);
      collapseTimerRef.current = window.setTimeout(() => {
        setKeepGroupMounted(false);
        setIsCollapsing(false);
        collapseTimerRef.current = null;
      }, GROUP_COLLAPSE_DURATION);
    }
  }, [clearGroupAnimationHandles, expanded, hasChildren, keepGroupMounted]);

  const handleSelect = React.useCallback(() => {
    if (disabled) {
      return;
    }

    setSelectedId(value);
  }, [disabled, setSelectedId, value]);

  const handleToggle = React.useCallback(
    (event: React.MouseEvent<HTMLButtonElement>) => {
      event.stopPropagation();

      if (disabled || !hasChildren) {
        return;
      }

      toggleExpanded(value);
    },
    [disabled, hasChildren, toggleExpanded, value],
  );

  const handleKeyDown = React.useCallback(
    (event: React.KeyboardEvent<HTMLDivElement>) => {
      if (disabled) {
        return;
      }

      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        handleSelect();
        return;
      }

      if (!hasChildren) {
        return;
      }

      if (event.key === 'ArrowRight' && !expanded) {
        event.preventDefault();
        toggleExpanded(value, true);
        return;
      }

      if (event.key === 'ArrowLeft' && expanded) {
        event.preventDefault();
        toggleExpanded(value, false);
      }
    },
    [disabled, expanded, handleSelect, hasChildren, toggleExpanded, value],
  );

  return (
    <li
      data-slot="jb-tree-item"
      data-value={value}
      className="jb-tree-item m-0 list-none p-0"
      {...props}
    >
      <div
        data-slot="jb-tree-item-button"
        data-value={value}
        data-has-children={hasChildren ? 'true' : undefined}
        data-selected={selected ? 'true' : undefined}
        data-disabled={disabled ? 'true' : undefined}
        data-expanded={hasChildren && expanded ? 'true' : undefined}
        data-level={level}
        role="treeitem"
        aria-level={level}
        aria-selected={selected}
        aria-expanded={hasChildren ? expanded : undefined}
        aria-disabled={disabled ? true : undefined}
        tabIndex={disabled ? -1 : 0}
        className={cn(
          'jb-tree-item-button relative box-border flex h-6 w-full min-w-0 cursor-default items-center gap-0.5 pr-4 pl-[var(--jb-tree-item-padding-left)] select-none outline-none transition-[color] duration-150 ease-in-out',
          className,
        )}
        style={resolvedItemButtonStyle}
        onClick={handleSelect}
        onDoubleClick={
          hasChildren && !disabled ? () => toggleExpanded(value) : undefined
        }
        onKeyDown={handleKeyDown}
      >
        <span
          aria-hidden="true"
          data-slot="jb-tree-item-overlay"
          className="jb-tree-item-overlay pointer-events-none absolute inset-y-0 left-3 right-3 rounded-[4px] transition-[background-color,box-shadow] duration-150 ease-in-out"
        />

        {hasChildren ? (
          <button
            data-slot="jb-tree-item-disclosure"
            data-value={value}
            data-expanded={expanded ? 'true' : undefined}
            type="button"
            className="jb-tree-item-disclosure relative z-10 inline-flex size-4 shrink-0 items-center justify-center border-0 bg-transparent p-0 outline-none"
            aria-label={
              expanded ? `Collapse ${textLabel}` : `Expand ${textLabel}`
            }
            onClick={handleToggle}
            disabled={disabled}
          >
            {expanded ? (
              <ChevronDownIcon className="size-4 scale-[0.78]" size={16} />
            ) : (
              <ChevronRightIcon className="size-4 scale-[0.78]" size={16} />
            )}
          </button>
        ) : (
          <span
            data-slot="jb-tree-item-disclosure-placeholder"
            aria-hidden="true"
            className="jb-tree-item-disclosure-placeholder relative z-10 inline-flex size-4 shrink-0 items-center justify-center"
          />
        )}

        <span
          data-slot="jb-tree-item-content"
          className="jb-tree-item-content relative z-10 inline-flex h-5 min-w-0 flex-1 items-center gap-1.5"
        >
          {icon ? (
            <span
              data-slot="jb-tree-item-icon"
              className="jb-tree-item-icon inline-flex size-4 shrink-0 items-center justify-center [&>svg]:size-4"
            >
              {icon}
            </span>
          ) : null}

          <span
            data-slot="jb-tree-item-label"
            className="jb-tree-item-label min-w-0 overflow-hidden text-ellipsis whitespace-nowrap"
          >
            {label}
          </span>

          {endContent ? (
            <span
              data-slot="jb-tree-item-end"
              className="jb-tree-item-end ml-auto pr-0.5 text-[13px] leading-4 font-medium"
            >
              {endContent}
            </span>
          ) : null}
        </span>
      </div>

      {hasChildren && keepGroupMounted ? (
        <TreeLevelContext.Provider value={level + 1}>
          <div
            data-slot="jb-tree-group-motion"
            data-expanded={groupExpanded ? 'true' : undefined}
            data-collapsing={isCollapsing ? 'true' : undefined}
            className="jb-tree-group-motion"
            onTransitionEnd={() => {
              if (!groupExpanded) {
                setKeepGroupMounted(false);
                setIsCollapsing(false);
              }
            }}
          >
            <ul
              data-slot="jb-tree-group"
              role="group"
              aria-hidden={!expanded}
              className="jb-tree-group m-0 list-none p-0"
            >
              {children}
            </ul>
          </div>
        </TreeLevelContext.Provider>
      ) : null}
    </li>
  );
}

export { Tree, TreeItem, type TreeItemProps, type TreeProps };

export default Tree;

:root {
  --jb-tree-bg: transparent;
  --jb-tree-text: var(--jb-gray-1);
  --jb-tree-muted: var(--jb-gray-7);
  --jb-tree-icon: var(--jb-gray-6);
  --jb-tree-disclosure: var(--jb-gray-7);
  --jb-tree-disclosure-hover: var(--jb-gray-5);
  --jb-tree-item-hover-bg: var(--jb-gray-12);
  --jb-tree-item-active-bg: var(--jb-gray-11);
  --jb-tree-item-selected-bg: var(--jb-blue-11);
  --jb-tree-item-selected-text: var(--jb-gray-1);
  --jb-tree-focus-ring: var(--jb-blue-4);
  --jb-tree-focus-ring-offset: var(--jb-gray-14);
  --jb-tree-disabled-text: var(--jb-gray-8);
}

.dark {
  --jb-tree-bg: transparent;
  --jb-tree-text: var(--jb-gray-12);
  --jb-tree-muted: var(--jb-gray-7);
  --jb-tree-icon: var(--jb-gray-10);
  --jb-tree-disclosure: var(--jb-gray-10);
  --jb-tree-disclosure-hover: var(--jb-gray-12);
  --jb-tree-item-hover-bg: var(--jb-gray-3);
  --jb-tree-item-active-bg: var(--jb-gray-4);
  --jb-tree-item-selected-bg: var(--jb-blue-2);
  --jb-tree-item-selected-text: var(--jb-gray-12);
  --jb-tree-focus-ring: var(--jb-blue-6);
  --jb-tree-focus-ring-offset: var(--jb-gray-2);
  --jb-tree-disabled-text: var(--jb-gray-7);
}

.jb-static-tree {
  background: var(--jb-tree-bg);
  color: var(--jb-tree-text);
  font-family: var(--jb-font-sans), sans-serif;
}

.jb-static-tree .jb-tree-group-motion {
  display: grid;
  grid-template-rows: 0fr;
  min-height: 0;
  opacity: 0;
  transform: translateY(-2px);
  pointer-events: none;
  transition:
    grid-template-rows 170ms var(--jb-ease-out),
    opacity 140ms var(--jb-ease-out),
    transform 170ms var(--jb-ease-out);
}

.jb-static-tree .jb-tree-group-motion[data-expanded='true'] {
  grid-template-rows: 1fr;
  opacity: 1;
  transform: translateY(0);
  pointer-events: auto;
}

.jb-static-tree .jb-tree-group-motion .jb-tree-group {
  min-height: 0;
  overflow: hidden;
}

.jb-static-tree .jb-tree-item-button {
  position: relative;
  color: var(--jb-tree-text);
  box-sizing: border-box;
}

.jb-static-tree .jb-tree-item-overlay {
  background-color: transparent;
}

.jb-static-tree .jb-tree-item-button:hover:not([data-disabled='true']) {
  background: transparent;
}

.jb-static-tree
  .jb-tree-item-button:hover:not([data-disabled='true']):not(
    [data-selected='true']
  )
  .jb-tree-item-overlay {
  background: var(--jb-tree-item-hover-bg);
}

.jb-static-tree .jb-tree-item-button:active:not([data-disabled='true']) {
  background: transparent;
}

.jb-static-tree
  .jb-tree-item-button:active:not([data-disabled='true']):not(
    [data-selected='true']
  )
  .jb-tree-item-overlay {
  background: var(--jb-tree-item-active-bg);
}

.jb-static-tree .jb-tree-item-button[data-selected='true'] {
  background: transparent;
  color: var(--jb-tree-item-selected-text);
}

.jb-static-tree
  .jb-tree-item-button[data-selected='true']
  .jb-tree-item-overlay {
  background: var(--jb-tree-item-selected-bg);
}

.jb-static-tree
  .jb-tree-item-button:focus-visible:not([data-disabled='true'])
  .jb-tree-item-overlay {
  box-shadow:
    0 0 0 1px var(--jb-tree-focus-ring-offset),
    0 0 0 3px var(--jb-tree-focus-ring);
}

.jb-static-tree .jb-tree-item-button[data-disabled='true'] {
  color: var(--jb-tree-disabled-text);
  cursor: not-allowed;
}

.jb-static-tree .jb-tree-item-disclosure {
  border: 0;
  background: transparent;
  padding: 0;
  color: var(--jb-tree-disclosure);
  outline: none;
}

.jb-static-tree .jb-tree-item-disclosure:disabled {
  cursor: not-allowed;
}

.jb-static-tree
  .jb-tree-item-button:not([data-selected='true']):not([data-disabled='true'])
  .jb-tree-item-disclosure:hover {
  color: var(--jb-tree-disclosure-hover);
}

.jb-static-tree .jb-tree-item-icon {
  color: var(--jb-tree-icon);
}

.jb-static-tree
  .jb-tree-item-button[data-disabled='true']
  .jb-tree-item-disclosure {
  color: var(--jb-tree-disabled-text);
}

.jb-static-tree .jb-tree-item-button[data-selected='true'] .jb-tree-item-icon,
.jb-static-tree
  .jb-tree-item-button[data-selected='true']
  .jb-tree-item-disclosure {
  color: currentColor;
}

.jb-static-tree .jb-tree-item-end {
  color: var(--jb-tree-muted);
}

'use client';

import * as React from 'react';

import { type ItemInstance } from '@headless-tree/core';
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuLabel,
  ContextMenuSeparator,
  ContextMenuTrigger,
} from '@/components/jetbrains-ui/context-menu';
import {
  ChevronDownIcon,
  ChevronRightIcon,
  LoaderIcon,
} from '@/components/jetbrains-ui/icons';
import { ScrollArea, ScrollViewport } from '@/components/jetbrains-ui/scroll-area';
import './index.css';

export { asyncDataLoaderFeature } from './feature';

export interface DynamicTreeItemData {
  label?: string;
  icon?: React.ReactNode;
  endContent?: React.ReactNode;
  disabled?: boolean;
  isFolder?: boolean;
}

export interface DynamicTreeItemProps<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> {
  item: ItemInstance<TItem>;
  indent: number;
}

export interface DynamicTreeItemComponent<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> {
  (props: DynamicTreeItemProps<TItem>): React.ReactNode;
}

export interface DynamicTreeContextMenuProps<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> {
  item: ItemInstance<TItem>;
}

export interface DynamicTreeContextMenuComponent<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> {
  (props: DynamicTreeContextMenuProps<TItem>): React.ReactNode;
}

export interface DynamicTreeProps<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> extends Omit<
    React.ComponentPropsWithoutRef<'div'>,
    'children' | 'className' | 'style' | 'contextMenu'
  > {
  containerProps: React.ComponentPropsWithoutRef<'div'>;
  items: ItemInstance<TItem>[];
  indent?: number;
  item?: DynamicTreeItemComponent<TItem>;
  contextMenu?: DynamicTreeContextMenuComponent<TItem> | null;
  width?: React.CSSProperties['width'];
  height?: React.CSSProperties['height'];
}

type DynamicTreeItemButtonStyle = React.CSSProperties & {
  '--jb-tree-item-padding-left': string;
};

type DynamicTreeAsyncItemInstance<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> = ItemInstance<TItem> & {
  invalidateItemData?: (optimistic?: boolean) => Promise<void>;
  invalidateChildrenIds?: (optimistic?: boolean) => Promise<void>;
};

type DynamicTreeMutableParentItem<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> = ItemInstance<TItem> & {
  updateCachedChildrenIds?: (
    childrenIds: string[],
    skipUpdateTree?: boolean,
  ) => void;
};

type DynamicTreeMutableItem<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> = ItemInstance<TItem> & {
  clearCachedChildren?: (skipUpdateTree?: boolean) => void;
};

function canRefreshDynamicTreeItem<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const asyncItem = item as DynamicTreeAsyncItemInstance<TItem>;

  return (
    typeof asyncItem.invalidateItemData === 'function' ||
    (item.isFolder() && typeof asyncItem.invalidateChildrenIds === 'function')
  );
}

function canDeleteDynamicTreeItem<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const parent = item.getParent() as
    | DynamicTreeMutableParentItem<TItem>
    | undefined;

  return typeof parent?.updateCachedChildrenIds === 'function';
}

function canClearDynamicTreeItemChildren<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const mutableItem = item as DynamicTreeMutableItem<TItem>;

  return (
    item.isFolder() && typeof mutableItem.clearCachedChildren === 'function'
  );
}

async function refreshDynamicTreeItem<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const asyncItem = item as DynamicTreeAsyncItemInstance<TItem>;

  if (typeof asyncItem.invalidateItemData === 'function') {
    await asyncItem.invalidateItemData();
  }

  if (
    item.isFolder() &&
    typeof asyncItem.invalidateChildrenIds === 'function'
  ) {
    await asyncItem.invalidateChildrenIds();
  }
}

function deleteDynamicTreeItem<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const parent = item.getParent() as
    | DynamicTreeMutableParentItem<TItem>
    | undefined;

  if (typeof parent?.updateCachedChildrenIds !== 'function') {
    return;
  }

  parent.updateCachedChildrenIds(
    parent
      .getChildren()
      .filter((child) => child.getId() !== item.getId())
      .map((child) => child.getId()),
  );
  parent.setFocused();
}

function clearDynamicTreeItemChildren<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const mutableItem = item as DynamicTreeMutableItem<TItem>;

  if (
    !item.isFolder() ||
    typeof mutableItem.clearCachedChildren !== 'function'
  ) {
    return;
  }

  item.setFocused();

  if (item.isExpanded()) {
    item.collapse();
  }

  mutableItem.clearCachedChildren();
}

export interface DynamicTreeItemContextMenuProps<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> extends DynamicTreeContextMenuProps<TItem> {}

function DynamicTreeItemContextMenu<TItem extends DynamicTreeItemData>({
  item,
}: DynamicTreeItemContextMenuProps<TItem>) {
  return (
    <>
      <ContextMenuLabel>
        {item.getItemData()?.label ?? item.getId()}
      </ContextMenuLabel>
      <ContextMenuItem
        inset
        disabled={!canRefreshDynamicTreeItem(item)}
        onSelect={() => {
          void refreshDynamicTreeItem(item);
        }}
      >
        Refresh
      </ContextMenuItem>
      <ContextMenuItem
        inset
        disabled={!canClearDynamicTreeItemChildren(item)}
        onSelect={() => {
          clearDynamicTreeItemChildren(item);
        }}
      >
        Clear Children
      </ContextMenuItem>
      <ContextMenuSeparator />
      <ContextMenuItem
        inset
        variant="destructive"
        disabled={!canDeleteDynamicTreeItem(item)}
        onSelect={() => {
          deleteDynamicTreeItem(item);
        }}
      >
        Delete
      </ContextMenuItem>
    </>
  );
}

function DynamicTreeItem<TItem extends DynamicTreeItemData>({
  indent,
  item,
}: DynamicTreeItemProps<TItem>) {
  const {
    style: resolvedStyle,
    tabIndex: resolvedTabIndex,
    ...resolvedProps
  } = item.getProps() as React.ComponentPropsWithoutRef<'div'>;

  return (
    <div
      data-slot="jb-tree-item"
      data-value={item.getId()}
      className="jb-tree-item my-0.5 p-0"
    >
      <div
        {...resolvedProps}
        data-slot="jb-tree-item-button"
        data-value={item.getId()}
        data-has-children={item.isFolder() ? 'true' : undefined}
        data-selected={item.isSelected() ? 'true' : undefined}
        data-disabled={
          (item.getItemData() as TItem | null)?.disabled ? 'true' : undefined
        }
        data-expanded={
          item.isFolder() && item.isExpanded() ? 'true' : undefined
        }
        data-loading={item.isLoading() ? 'true' : undefined}
        aria-selected={item.isSelected()}
        aria-disabled={
          (item.getItemData() as TItem | null)?.disabled ? true : undefined
        }
        aria-busy={item.isLoading() ? true : undefined}
        tabIndex={
          (item.getItemData() as TItem | null)?.disabled
            ? -1
            : (resolvedTabIndex ?? -1)
        }
        style={
          {
            ...resolvedStyle,
            '--jb-tree-item-padding-left': `${
              16 +
              item.getItemMeta().level * indent +
              Math.max(0, item.getItemMeta().level - 1) * 2
            }px`,
          } as DynamicTreeItemButtonStyle
        }
        className="jb-tree-item-button relative box-border flex h-6 w-full min-w-0 cursor-default items-center gap-0.5 pr-4 pl-[var(--jb-tree-item-padding-left)] select-none outline-none transition-[color] duration-150 ease-in-out data-[disabled=true]:cursor-not-allowed"
      >
        <span
          aria-hidden="true"
          data-slot="jb-tree-item-overlay"
          className="jb-tree-item-overlay pointer-events-none absolute inset-y-0 left-3 right-3 rounded-[4px] transition-[background-color,box-shadow] duration-150 ease-in-out"
        />

        {item.isFolder() ? (
          <button
            data-slot="jb-tree-item-disclosure"
            data-value={item.getId()}
            data-expanded={item.isExpanded() ? 'true' : undefined}
            data-loading={item.isLoading() ? 'true' : undefined}
            type="button"
            className="jb-tree-item-disclosure relative z-10 inline-flex size-4 shrink-0 items-center justify-center border-0 bg-transparent p-0 outline-none disabled:cursor-not-allowed"
            aria-label={
              item.isLoading()
                ? `Loading ${(item.getItemData() as TItem | null)?.label ?? item.getId()}`
                : item.isExpanded()
                  ? `Collapse ${(item.getItemData() as TItem | null)?.label ?? item.getId()}`
                  : `Expand ${(item.getItemData() as TItem | null)?.label ?? item.getId()}`
            }
            onClick={(event) => {
              event.stopPropagation();

              if ((item.getItemData() as TItem | null)?.disabled) {
                return;
              }

              item.setFocused();

              if (item.isExpanded()) {
                item.collapse();
              } else {
                item.expand();
              }
            }}
            disabled={Boolean((item.getItemData() as TItem | null)?.disabled)}
          >
            {item.isLoading() ? (
              <LoaderIcon
                className="size-4 [animation-duration:900ms]"
                size={16}
              />
            ) : item.isExpanded() ? (
              <ChevronDownIcon className="size-4 scale-[0.78]" size={16} />
            ) : (
              <ChevronRightIcon className="size-4 scale-[0.78]" size={16} />
            )}
          </button>
        ) : (
          <span
            data-slot="jb-tree-item-disclosure-placeholder"
            aria-hidden="true"
            className="jb-tree-item-disclosure-placeholder relative z-10 inline-flex size-4 shrink-0 items-center justify-center"
          />
        )}
        <span
          data-slot="jb-tree-item-content"
          className="jb-tree-item-content relative z-10 inline-flex h-5 min-w-0 flex-1 items-center gap-1.5"
        >
          {(item.getItemData() as TItem | null)?.icon ? (
            <span
              data-slot="jb-tree-item-icon"
              className="jb-tree-item-icon inline-flex size-4 shrink-0 items-center justify-center [&>svg]:size-4"
            >
              {(item.getItemData() as TItem | null)?.icon}
            </span>
          ) : null}

          <span
            data-slot="jb-tree-item-label"
            className="jb-tree-item-label min-w-0 overflow-hidden text-ellipsis whitespace-nowrap"
          >
            {(item.getItemData() as TItem | null)?.label ?? item.getId()}
          </span>

          {(item.getItemData() as TItem | null)?.endContent ? (
            <span
              data-slot="jb-tree-item-end"
              className="jb-tree-item-end ml-auto pr-0.5 text-[13px] leading-4 font-medium"
            >
              {(item.getItemData() as TItem | null)?.endContent}
            </span>
          ) : null}
        </span>
      </div>
    </div>
  );
}

function DynamicTree<TItem extends DynamicTreeItemData>({
  containerProps,
  items,
  indent = 16,
  item: customItem,
  contextMenu,
  width,
  height,
  ...props
}: DynamicTreeProps<TItem>) {
  const ItemComponent = customItem ?? DynamicTreeItem;
  const ContextMenuComponent =
    contextMenu === undefined
      ? (DynamicTreeItemContextMenu as DynamicTreeContextMenuComponent<TItem>)
      : contextMenu;

  return (
    <ScrollArea
      data-slot="jb-tree-scroll-area"
      className="max-w-full p-2"
      style={{ width, height }}
    >
      <ScrollViewport data-slot="jb-tree-scroll-viewport" className="size-full">
        <div
          {...containerProps}
          data-slot="jb-tree"
          className="jb-tree jb-dynamic-tree block w-full min-w-[244px] box-border py-2 text-[13px] leading-4 font-medium [font-family:var(--jb-font-sans),sans-serif]"
          {...props}
        >
          {items.map((item) => {
            if (!ContextMenuComponent) {
              return (
                <ItemComponent
                  key={item.getKey()}
                  item={item}
                  indent={indent}
                />
              );
            }

            return (
              <ContextMenu key={item.getKey()}>
                <ContextMenuTrigger
                  asChild
                  onContextMenu={(event) => {
                    if ((item.getItemData() as TItem | null)?.disabled) {
                      event.preventDefault();
                      return;
                    }

                    item.setFocused();
                    item.select();
                  }}
                >
                  <div
                    data-slot="jb-tree-item-context-trigger"
                    data-value={item.getId()}
                  >
                    <ItemComponent item={item} indent={indent} />
                  </div>
                </ContextMenuTrigger>
                <ContextMenuContent>
                  {ContextMenuComponent({
                    item,
                  })}
                </ContextMenuContent>
              </ContextMenu>
            );
          })}
        </div>
      </ScrollViewport>
    </ScrollArea>
  );
}

